SET @scoop_duke_id = (SELECT id FROM partners WHERE businessName = 'Scoop Duke DFW' LIMIT 1);
SET @green_thumb_id = (SELECT id FROM partners WHERE businessName = 'Green Thumb Lawn Care' LIMIT 1);
SET @job_lovers = (SELECT id FROM jobs WHERE serviceAddress = '3301 Lovers Ln, Dallas, TX 75225' LIMIT 1);
SET @job_gaston = (SELECT id FROM jobs WHERE serviceAddress = '5519 Gaston Ave, Dallas, TX 75214' LIMIT 1);

-- Outbound referrals Scoop Duke sent to Green Thumb
INSERT INTO opportunities (jobId, sourcePartnerId, receivingPartnerId, opportunityType, opportunityCategory, description, aiConfidence, status, estimatedJobValue, actualJobValue, referralCommissionAmount, sentAt, acceptedAt, jobClosedAt, createdAt)
VALUES
  (@job_lovers, @scoop_duke_id, @green_thumb_id, 'lawn_mowing', 'Outdoor & Lawn', 'Grass overgrown 6+ inches across full yard. Homeowner confirmed no current lawn service. Excellent recurring opportunity.', 0.96, 'converted', 280.00, 265.00, 13.25, DATE_SUB(NOW(), INTERVAL 11 DAY), DATE_SUB(NOW(), INTERVAL 10 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 11 DAY)),
  (@job_gaston, @scoop_duke_id, @green_thumb_id, 'lawn_mowing', 'Outdoor & Lawn', 'Overgrown hedges and lawn needing full trim. Broken fence panel also spotted.', 0.89, 'accepted', 195.00, NULL, NULL, DATE_SUB(NOW(), INTERVAL 19 DAY), DATE_SUB(NOW(), INTERVAL 18 DAY), NULL, DATE_SUB(NOW(), INTERVAL 19 DAY));

-- Commission for the converted referral
SET @converted_opp = (SELECT id FROM opportunities WHERE jobId = @job_lovers AND status = 'converted' LIMIT 1);

INSERT INTO commissions (opportunityId, payingPartnerId, receivingPartnerId, commissionType, amount, jobValue, feeRate, description, paid, createdAt)
VALUES
  (@converted_opp, @green_thumb_id, @scoop_duke_id, 'referral_commission', 13.25, 265.00, 0.0500, 'Referral commission: Scoop Duke → Green Thumb, 3301 Lovers Ln', false, DATE_SUB(NOW(), INTERVAL 3 DAY));

